CREATE TABLE lead_submissions (id uuid PRIMARY KEY DEFAULT concourse.uuid_generate_v7(), event_id uuid NOT NULL REFERENCES events(id) ON DELETE CASCADE, event_exhibitor_id uuid NOT NULL REFERENCES event_exhibitors(id) ON DELETE CASCADE, attendee_user_id uuid REFERENCES users(id) ON DELETE SET NULL, lead_form_id uuid NOT NULL REFERENCES lead_forms(id) ON DELETE RESTRICT, interaction_source text NOT NULL, potential_duplicate boolean NOT NULL DEFAULT false, submitted_at timestamptz NOT NULL DEFAULT now(), CONSTRAINT lead_submissions_interaction_source_check CHECK (interaction_source IN ('visitor_qr','exhibitor_device')));
CREATE INDEX lead_submissions_exhibitor_submitted_at_idx ON lead_submissions(event_exhibitor_id, submitted_at); CREATE INDEX lead_submissions_exhibitor_attendee_idx ON lead_submissions(event_exhibitor_id, attendee_user_id);
CREATE TABLE lead_submission_values (id uuid PRIMARY KEY DEFAULT concourse.uuid_generate_v7(), lead_submission_id uuid NOT NULL REFERENCES lead_submissions(id) ON DELETE CASCADE, lead_form_field_id uuid NOT NULL REFERENCES lead_form_fields(id) ON DELETE RESTRICT, value jsonb, field_snapshot jsonb NOT NULL, created_at timestamptz NOT NULL DEFAULT now());
CREATE UNIQUE INDEX lead_submission_values_submission_field_key ON lead_submission_values(lead_submission_id, lead_form_field_id); CREATE INDEX lead_submission_values_submission_id_idx ON lead_submission_values(lead_submission_id);
GRANT SELECT, INSERT ON lead_submissions, lead_submission_values TO app_tenant; GRANT ALL PRIVILEGES ON lead_submissions, lead_submission_values TO app_platform;
ALTER TABLE lead_submissions ENABLE ROW LEVEL SECURITY; ALTER TABLE lead_submissions FORCE ROW LEVEL SECURITY; CREATE POLICY tenant_isolation ON lead_submissions USING (event_exhibitor_id IN (SELECT id FROM event_exhibitors WHERE organization_id = current_setting('app.current_org_id', true)::uuid)) WITH CHECK (event_exhibitor_id IN (SELECT id FROM event_exhibitors WHERE organization_id = current_setting('app.current_org_id', true)::uuid));
ALTER TABLE lead_submission_values ENABLE ROW LEVEL SECURITY; ALTER TABLE lead_submission_values FORCE ROW LEVEL SECURITY; CREATE POLICY tenant_isolation ON lead_submission_values USING (lead_submission_id IN (SELECT id FROM lead_submissions)) WITH CHECK (lead_submission_id IN (SELECT id FROM lead_submissions));
CREATE FUNCTION concourse.exhibitor_can_read_attendee_profile(target_user_id uuid) RETURNS boolean LANGUAGE sql STABLE SECURITY DEFINER SET search_path = public AS $$ SELECT EXISTS (SELECT 1 FROM lead_submissions submission JOIN event_exhibitors exhibitor ON exhibitor.id = submission.event_exhibitor_id WHERE submission.attendee_user_id = target_user_id AND exhibitor.organization_id = NULLIF(current_setting('app.current_org_id', true), '')::uuid); $$;
GRANT EXECUTE ON FUNCTION concourse.exhibitor_can_read_attendee_profile(uuid) TO app_tenant;
CREATE POLICY authorized_exhibitor_profile_read ON users FOR SELECT USING (concourse.exhibitor_can_read_attendee_profile(id));
